def to_negabinary(n):
    if n == 0: return "0"
    res = ""
    while n != 0:
        n, rem = divmod(n, -2)
        if rem < 0:
            rem += 2
            n += 1
        res = str(rem) + res
    return res

if __name__ == "__main__":
    print(f"-19 in base -2: {to_negabinary(-19)}")
